import {
  html,
  customElement,
  state,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbWorkspaceViewElement } from "@umbraco-cms/backoffice/workspace";
import type { FormSecurityForUser } from "@umbraco-forms/generated";
import type { UUIBooleanInputEvent } from "@umbraco-cms/backoffice/external/uui";
import { FORMS_SECURITY_USER_WORKSPACE_CONTEXT } from "../../security-user-workspace.context-token.js";
import type { PackagePermissionsSecurityBase } from "../../../entities.js";
import type { FormsSecurityUserWorkspaceContext } from "../../security-user-workspace.context.js";
import { UmbWorkspaceViewSecurityPermissionsBaseElement } from "./workspace-view-security-permissions-base.element.js";

const elementName = "workspace-view-security-user-permissions";

@customElement(elementName)
export class UmbWorkspaceViewSecurityUserPermissionsElement
  extends UmbWorkspaceViewSecurityPermissionsBaseElement<FormsSecurityUserWorkspaceContext>
  implements UmbWorkspaceViewElement
{
  @state()
  _security?: FormSecurityForUser;

  constructor() {
    super(FORMS_SECURITY_USER_WORKSPACE_CONTEXT.contextAlias);
  }

  observeSecurityItem() {
    if (!this.workspaceContext) return;

    this.observe(this.workspaceContext.data, (security) => {
      if (!security) return;
      this._security = security;
    });
  }

  onPackagePermissionsChange(
    e: UUIBooleanInputEvent,
    permission: keyof PackagePermissionsSecurityBase
  ) {
    const value = e.target.checked;

    this.workspaceContext?.setUserSecurityProperty(permission, value);

    if (permission === "viewEntries" && !value) {
      this.workspaceContext?.setUserSecurityProperty("editEntries", false);
      this.workspaceContext?.setUserSecurityProperty("deleteEntries", false);
    }

    this.dispatchEvent(new CustomEvent("valueChange"));
    this.requestUpdate();
  }

  render() {
    return html`
      ${this.renderToggles(this._security?.userSecurity)}
      ${this.renderStartFolders(this._security?.startFolderIds ?? [])}
      ${this.renderSecurityTable(this._security?.formsSecurity ?? [])}
    `;
  }
}

export default UmbWorkspaceViewSecurityUserPermissionsElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: UmbWorkspaceViewSecurityUserPermissionsElement;
  }
}
